(function(){"use strict";var y=document.getElementById("year");if(y)y.textContent=new Date().getFullYear();var n=document.querySelector(".nav-toggle"),o=document.querySelector(".nav-overlay"),l=document.querySelectorAll(".main-nav a");function c(){document.body.classList.remove("nav-open");n&&n.setAttribute("aria-expanded","false")}function t(){document.body.classList.add("nav-open");n&&n.setAttribute("aria-expanded","true")}n&&n.addEventListener("click",function(){document.body.classList.contains("nav-open")?c():t()});o&&o.addEventListener("click",c);l.forEach(function(e){e.addEventListener("click",c)});document.addEventListener("keydown",function(e){e.key==="Escape"&&document.body.classList.contains("nav-open")&&c()});var p=document.querySelector(".pricing-table"),b=document.querySelectorAll(".pricing-toggle-btn");if(p&&b.length)b.forEach(function(e){e.addEventListener("click",function(){var r=this.getAttribute("data-period");b.forEach(function(t){t.classList.toggle("active",t.getAttribute("data-period")===r);t.setAttribute("aria-pressed",t.getAttribute("data-period")===r?"true":"false")});p.classList.toggle("annual",r==="annual");var a=p.querySelectorAll(".pricing-amount");a.forEach(function(t){var n=t.getAttribute("data-monthly"),o=t.getAttribute("data-annual");n&&o&&(t.textContent="$"+(r==="annual"?o:n))})})})})();
